class ParseError(Exception):
    pass
try:
    raise ParseError("fila 3") from ValueError("bad int")
except ParseError as e:
    print(e, "cause", type(e.__cause__).__name__)

def parse_age(s):
    try:
        return int(s)
    except ValueError as e:
        raise ValueError(f"edad inválida: {s!r}") from e
try:
    parse_age("x")
except ValueError as e:
    print(e, e.__cause__)

def load_config(cfg):
    if not cfg.get("delimiter"):
        raise SystemExit("fail-fast: delimiter vacío")
    return cfg["delimiter"]
try:
    load_config({"delimiter": ""})
except SystemExit as e:
    print(e)

def classify_error(kind):
    return "fail_fast" if kind == "config" else "quarantine"
print(classify_error("config"), classify_error("row"))

def mask_email(e: str) -> str:
    local, _, domain = e.partition("@")
    if not domain:
        return "***"
    return f"{local[:1]}***@{domain}"
print(mask_email("ana@ejemplo.pe"))

def should_retry(exc):
    return type(exc).__name__ in {"TimeoutError", "ConnectionError"}
print(should_retry(TimeoutError()))
print(should_retry(ValueError("bad")))

