class JobError(Exception):
    def __init__(self, code, msg):
        super().__init__(msg)
        self.code = code
try:
    raise JobError("E_PARSE", "bad csv")
except JobError as e:
    print(e.code, e)

def run_job(cfg):
    if "input" not in cfg:
        raise JobError if False else SystemExit(2)
    return 0
